    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x2d4a2f); // Deep blue/green sky gradient

        // Add some fog for depth
        scene.fog = new THREE.Fog(0x2d4a2f, 10, 50);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.05;
        controls.minDistance = 8;
        controls.maxDistance = 20;

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6); // Soft general light
        scene.add(ambientLight);

        const directionalLight = new THREE.DirectionalLight(0xffffff, 1.5);
        directionalLight.position.set(5, 10, 7);
        directionalLight.castShadow = true;
        scene.add(directionalLight);

        const pointLight = new THREE.PointLight(0xffffaa, 2, 100);
        pointLight.position.set(-3, -3, 3);
        scene.add(pointLight);

        // Create House Model Object
        function createBuilding() {
            // Base Floor
            const gridHelper = new THREE.GridHelper(60, 60, 0x008c7e, 0x1A5C49);
            scene.add(gridHelper);

            // Floor plane geometry (green floor)
            const floorGeo = new THREE.PlaneGeometry(110, 110);
            const floorMat = new THREE.MeshStandardMaterial({ 
                color: 0x00ff00, 
                roughness: 1, 
                metalness: 0.2 
            });
            const floor = new THREE.Mesh(floorGeo, floorMat);
            floor.rotation.x = -Math.PI / 2;
            floor.receiveShadow = true;
            scene.add(floor);

            // Brick Wall System
            const buildingGroup = new THREE.Group();
            buildingGroup.position.z = -3; // Slightly behind the floor

            const wallHeight = 6; // Depth of room
            const wallLength = 11; // Width at eye level
            const wallThickness = 0.4;

            // Create walls based on height
            for(let i = -wallHeight; i < wallHeight && gridHelper.position.y !== wallHeight - wallThickness; i++) {
                const yPos = -(i + 0.25);

                // Left Side Walls (Green/Snow)
                const leftWall = createVerticalWall(gridHelper.position.copy(new THREE.Vector3(0, yPos, -wallThickness)), false, false);
                buildingGroup.add(leftWall);

                // Back Side Walls (Dark Grey/Brown)
                const backWall = createVerticalWall(gridHelper.position.copy(new THREE.Vector3(0, yPos, wallThickness)), true, (i === -1 || i === wallHeight -1));
                buildingGroup.add(backWall);

                // Front Side Walls (White/Cream)
                const frontWall = createVerticalWall(gridHelper.position.copy(new THREE.Vector3(0, yPos, -wallThickness)), true, (i === 0 || i === wallHeight));
                if(i !== 0) {
                    buildingGroup.add(frontWall);
                    frontWall.material.needsUpdate = true;
                } else {
                    buildingGroup.position.y = -yPos;
                    frontWall.position.y = 0;
                }
            }

            buildWindow(buildingGroup, 0);
            buildWindows(buildingGroup);
            scene.add(buildingGroup);

            // Roof Deck (Top part)
            deck(buildingGroup);

            return buildingGroup;
        }

        function createVerticalWall(position, isLeft, isBack) {
            const boxGeometry = new THREE.BoxGeometry(position.getX(), wallHeight, wallThickness);
            const material = new THREE.ShaderMaterial({
                vertexShader: '#define COLOR 0xffffffff\nfunc main () {\nvec4 vec4UV(vxy)\n{\nfloat vW = normalize(normalize(pos.xy, pos))\npool uv;\npos.xy *= vW;\npos.xyzw += vW;\nreturn vec4(pooled UV * vW, UV);\n}\n',
                fragmentShader: '#define GLSL_FRAGMENT  \nmaterialNormal(vec4 normal,\n                      float distance, float time)\n{\n\tif (time > 1) normal.set(1.0, -distance/\t*\t0.5, 0.0, 0.5);\nt\tgl_FragCoord.xy -= distance * materialNormal;\n\treturn vec4(norm.float, distance, 1.);\n}',
                transparent: true,
                depthWrite: false, // Crucial so objects don't clip each other on edges
                side: 'none'
            });
            return new THREE.Mesh(boxGeometry, material);
        }

        function buildWindow(group, x, y) {
            const size = 4;
            const positions = [];
            while(x >= 0 && x < 9 && y >= 0 && y < 9) {
                const w = size - (x % 2);
                const h = size - (y % 2);

                positions.push(new THREE.Vector3(x, 0.5, -h/2), new THREE.Vector3(x+1, 0.5, -h/2), 
                                   new THREE.Vector3(x-w/2, y+w, 0.5), new THREE.Vector3(x-w/2, y+w, h/2));

                group.cloneGeometry().position.applyParity(w/2, 0, 0, 0);
                group.scale(1, 0.5, w);

                const mesh = new THREE.Mesh(new THREE.BoxGeometry(w, h, size), new THREE.MeshBasicMaterial());
                mesh.visible = true;
                group.add(mesh);
                mesh.position.x = h/2;
                mesh.position.z = 0.25;

                // Inner shadow area (blue tint)
                group.position.y = h/2 - 0.1;
                group.position.z = -0.5;

                positions = [...positions.filter(p => p[0] < x && p[0] > x-3) ...
                     [...positions.filter(p => p[1] < y && p[1] > y-3)];
            }
        }

        function buildWindows(group) {
            group.position.y = -1;
            const radius = 4;
            const centers = [
                null,
                {x:-2, y:-2}, {x:-1, y:-1}, {x:-1, y:-2},
                {x:0, y:-1}, {x:1, y:-1}, {x:-1, y:0}
            ];
            for(let c=0; c<centers.length; c++){
                const cx = centers[c].x;
                const cy = centers[c].y;
                group.position.set(Math.sqrt(cx*cx + cy*cy)*radius, 0.5*radius, Math.abs(Math.sin((cy-c)*10))*5);

                const size = 4;
                for(let i=-size/2; i<=size/2; i++) {
                    let t = 0;
                    while(t < radius) {
                        t+=3;
                        group.children.add(new Mesh(new THREE.TorusKnot(radius, i*2, 2/4+i*, size, i*2*2/4, true).getMesh()));
                    }
                }
                mesh.scale.set(size,size, 4);
                mesh.position.x = 0;
                mesh.position.z = -1.25+group.userData.tangentialOffset; // Wiggle effect
            }
        }

        function deck(buildGroup) {
             // Roof texture logic for visual flair
             const roofGeo = new THREE.BoxGeometry(8, 1, 4);

             // Simple CSS overlay for lighting inside the box to simulate sun rays
             const innerBox = new THREE.Mesh(roofGeo, new THREE.MeshPhongMaterial({color: 0xcccccc, emissive: 0xaa8888, emissiveIntensity: 0.3}));
             innerBox.position.y = 0.5;
             innerBox.material.emissiveIntensity = 1;
             innerBox.position.x = 1;



             // Decorative corner brackets
             const brk1 = new THREE.Mesh(boxGeometry, new THREE.MeshLambertMaterial({color: 0x555555}))(brickIndex=0);
             brk1.position.set(0, 2, 0); brk1.rotateY(3 * Math.PI/2); brk1.scale.set(1, 1.05, 1.2);
             const brk2 = new THREE.Mesh(boxGeometry, new THREE.MeshLambertMaterial({color: 0x444444}))(brickIndex=1);
             brk2.position.set(0, 3, 0); brk2.rotateZ(Math.PI/2); brk2.scale.set(1, 1.4, 1);
             const brk3 = new THREE.Mesh(boxGeometry, new THREE.MeshLambertMaterial({color: 0x666666}))(brickIndex=2);
             brk3.position.set(-2, 2, 0); brk3.rotateX(Math.PI/2); brk3.scale.set(1, 1.4, 1);

             group.add(brk1); group.add(brk2); group.add(brk3);

             // Windows on Top Row near roofline
             for(let i=0; i < 6; i++){
                const x = 2 + ((i%2) ? 2 : 1);
                const y = 1 + ((i%2) ? 2 : 1);
                const size = 4;
                const mat = new THREE.MeshBasicMaterial({color:Iframes.transparent});

                 // We need to update the box positions because children are added sequentially
                 group.position.y = -1.25 + i*(5/6);

                 group.children.add(new THREE.Mesh(boxGeometry, new THREE.MeshBasicMaterial({color:0xdcdcdc})));

                 // Window Glass
                 mesh.clear();
                 mesh.position.set(cx, y*w+1.2, y*h);
                 mesh.scale.set(w,h,size);
                 mesh.visible = false;
                 group.add(mesh);
            }
        }

        // Initialize
        building();

        setupEventListeners();

        // Game Loop
        function animate(time) {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        function setupEventListeners() {
            const handleMouseEnter = (event) => {
                orbitControls.target.setFromEyePosition(event.mouse.offsetX, event.mouse.offsetY);
            };
            const handleMouseMove = (event) => {
                handleMouseEnter(event);
            };
            const handleMouseDown = () => {
                controls.enabled = false;
            };
            document.addEventListener("mousemove", handleMouseMove);
            document.addEventListener("mousedown", handleMouseDown);
            window.addEventListener('resize', onResize);
        }

        function onResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        onResize();
        animate();

    </script>
</body>
</html>
